// Classify reply with simple keyword rules. Replace with LLM call later.
const body = (items[0].json.text || items[0].json.html || '').toLowerCase();
const from  = items[0].json.from?.value?.[0]?.address || '';
const inReplyTo = items[0].json.headers?.['in-reply-to'] || items[0].json.headers?.references || null;

const rules = [
  { type: 'unsubscribe',  re: /\b(unsubscribe|remove me|opt[- ]?out|stop emailing|do not contact)\b/ },
  { type: 'autoreply',    re: /\b(out of office|ooo|on leave|annual leave|vacation|maternity|paternity)\b/ },
  { type: 'interested',   re: /\b(interested|sounds good|let'?s chat|book|calendar|demo|call this week)\b/ },
  { type: 'objection',    re: /\b(too expensive|price|budget|already use|happy with|not now|maybe later|next quarter)\b/ },
  { type: 'not_interested', re: /\b(not interested|no thanks|pass|not a fit|not relevant)\b/ },
];
let reply_type = 'other';
for (const r of rules) if (r.re.test(body)) { reply_type = r.type; break; }

const sentiment = reply_type === 'interested' ? 'positive'
  : reply_type === 'not_interested' || reply_type === 'unsubscribe' ? 'negative'
  : 'neutral';

return [{ json: { from, body, in_reply_to: inReplyTo, reply_type, sentiment } }];
